import React from 'react';

/** Grid row 4/5/6 cột — `voucher-header-compact.md` · class từ `documentForm.module.css` */
export const VoucherFormRow: React.FC<{
  styles: { row4?: string; row5?: string; row6?: string };
  columns?: 4 | 5 | 6;
  className?: string;
  children: React.ReactNode;
}> = ({ styles, columns = 4, className, children }) => {
  const rowClass =
    columns === 6 ? styles.row6 : columns === 5 ? styles.row5 : styles.row4;
  return <div className={[rowClass, className].filter(Boolean).join(' ')}>{children}</div>;
};
