import { masterService } from '../services/master/masterService';
import type { CustomerDto } from '../services/master/models';

export function customerFieldHandlers(
  setCustomerId: (v: string) => void,
  setCustomerCode: (v: string) => void,
  setCustomerName: (v: string) => void,
) {
  return {
    onSelect: (c: CustomerDto) => {
      setCustomerId(c.customerId);
      setCustomerCode(c.code);
      setCustomerName(c.name);
    },
    onClear: () => {
      setCustomerId('');
      setCustomerCode('');
      setCustomerName('');
    },
  };
}

export async function loadCustomerDisplay(
  customerId: string,
  fallbackName = '',
): Promise<{ code: string; name: string }> {
  if (!customerId) return { code: '', name: '' };
  try {
    const c = await masterService.getCustomer(customerId);
    return { code: c.code, name: c.name };
  } catch {
    return { code: '', name: fallbackName };
  }
}
